solution_code:
#include <iostream>
#include <string>

int main() {
    int n;
    std::cin >> n;
    std::string store[5];
    for (int i = 0; i < n; ++i) {
        std::string s;
        std::cin >> s;
        store[i] = std::move(s);
    }
    for (int i = 0; i < n; ++i) {
        std::cout << store[i] << "\n";
    }
    return 0;
}

