solution_code:
#include <iostream>
#include <string>

void swap_strings(std::string& a, std::string& b) {
    std::string tmp = std::move(a);
    a = std::move(b);
    b = std::move(tmp);
}

int main() {
    std::string a, b;
    std::cin >> a >> b;
    swap_strings(a, b);
    std::cout << a << "\n";
    std::cout << b << "\n";
    return 0;
}
